INSERT INTO `ai_message` VALUES (1993306833503940609, 1993306803149762562, 'assistant', '思考: 用户刚刚开始对话，尚未提供具体需求或偏好，需要引导其说明旅游兴趣、时间安排和关注点。  \n行动: 主动询问用户的旅游计划细节，以便提供个性化建议。  \n观察: 您好！欢迎咨询从化旅游信息。请问您是想了解哪些方面的内容呢？比如：\n\n- 想去哪些类型的景点（自然风光、乡村体验、温泉休闲等）？\n- 计划游玩几天？是否有具体的时间安排？\n- 对当地美食是否感兴趣？\n- 是否需要包含住宿和路线的完整行程规划？\n\n告诉我您的需求，我将为您定制合适的从化旅行方案！', NULL, 7076, '2025-11-25 21:12:38', 0);
INSERT INTO `ai_message` VALUES (1993306833566855170, 1993306803149762562, 'assistant', '思考: 用户刚刚开始对话，尚未提供具体需求或偏好，需要引导其说明旅游兴趣、时间安排和关注点。  \n行动: 主动询问用户的旅游计划细节，以便提供个性化建议。  \n观察: 您好！欢迎咨询从化旅游信息。请问您是想了解哪些方面的内容呢？比如：\n\n- 想去哪些类型的景点（自然风光、乡村体验、温泉休闲等）？\n- 计划游玩几天？是否有具体的时间安排？\n- 对当地美食是否感兴趣？\n- 是否需要包含住宿和路线的完整行程规划？\n\n告诉我您的需求，我将为您定制合适的从化旅行方案！', NULL, 7152, '2025-11-25 21:12:38', 0);

-- ----------------------------
-- Table structure for ai_task
-- ----------------------------
DROP TABLE IF EXISTS `ai_task`;
CREATE TABLE `ai_task`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `task_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `biz_key` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `payload` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `status` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `retry_count` int NULL DEFAULT 0,
  `max_retry` int NULL DEFAULT 3,
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `user_id` bigint NULL DEFAULT NULL,
  `trip_id` bigint NULL DEFAULT NULL,
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uniq_task_id`(`task_id` ASC) USING BTREE,
