-- ----------------------------
-- Table structure for merchant
-- ----------------------------
DROP TABLE IF EXISTS `merchant`;
CREATE TABLE `merchant`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint NOT NULL COMMENT '关联用户表ID',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '店铺名称',
  `type` tinyint NOT NULL COMMENT '类型: 1-美食, 2-工艺品, 3-农产品, 4-酒店, 5-娱乐',
  `introduction` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '店铺简介',
  `cover_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '封面图',
  `logo_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '店铺Logo',
  `longitude` decimal(9, 6) NULL DEFAULT NULL COMMENT '经度',
  `latitude` decimal(9, 6) NULL DEFAULT NULL COMMENT '纬度',
  `location` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '具体地址',
  `open_hours` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '营业时间',
  `contact_phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '联系电话',
  `rating` decimal(3, 1) NULL DEFAULT 0.0 COMMENT '平均评分',
  `status` tinyint NULL DEFAULT 1 COMMENT '状态: 0-歇业, 1-营业中, 2-审核中, 3-禁用',
  `min_price` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '最低商品价格(用于筛选)',
  `max_price` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '最高商品价格(用于筛选)',
  `tags` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '标签(JSON格式,如[\"网红店\",\"老字号\"])',
  `business_hours` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '营业时间描述',
  `service_score` decimal(2, 1) NULL DEFAULT 5.0 COMMENT '服务评分',
  `environment_score` decimal(2, 1) NULL DEFAULT 5.0 COMMENT '环境评分',
  `feature_tags` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '特色标签(JSON格式)',
  `is_verified` tinyint NULL DEFAULT 0 COMMENT '是否认证商家',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `is_delete` tinyint NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_type`(`type` ASC) USING BTREE,
  INDEX `idx_location`(`longitude` ASC, `latitude` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_name`(`name` ASC) USING BTREE,
  INDEX `idx_rating`(`rating` ASC) USING BTREE,
  INDEX `idx_price_range`(`min_price` ASC, `max_price` ASC) USING BTREE,
  INDEX `idx_is_verified`(`is_verified` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '商家主表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of merchant
-- ----------------------------
INSERT INTO `merchant` VALUES (1, 1973987306786885634, '从化老字号美食坊', 1, '从化本地正宗美食，传承百年老手艺。以新鲜食材和传统烹饪技法，为您呈现最地道的岭南风味。推荐菜品：蒸排骨、白切鸡、煲仔饭。', 'https://bpic.588ku.com/back_list_pic/22/01/12/aa22da1fc25f978d109e9729bd5aab9e.jpg', 'https://img.picgo.net/20241217/logo-food.png', 113.586389, 23.548309, '广州市从化区街口街道建设路88号', '周一至周日 10:00-22:00', '020-87901234', 4.8, 1, 30.00, 200.00, '[\"老字号\",\"粤菜\",\"性价比高\"]', '周一至周日 10:00-22:00', 4.9, 4.7, '[\"停车位\",\"WiFi\",\"包厢\"]', 1, '2025-10-17 18:23:10', '2025-11-18 17:01:31', 1);
INSERT INTO `merchant` VALUES (2, 1973987306786885634, '流溪河精品民宿', 4, '坐落在流溪河畔的精品民宿，环境优美，设施齐全。每间客房都配有独立阳台，可欣赏山景水色。提供早餐、免费停车等服务。是度假休闲的理想选择。', 'https://ts1.tc.mm.bing.net/th/id/R-C.4da110c44b9323a0bcb5a92877425c9b?rik=L4P%2bj%2bq%2fg2aLKA&riu=http%3a%2f%2fn.sinaimg.cn%2fsinakd20113%2f607%2fw640h767%2f20210306%2fd62e-kkxpcze0493202.jpg&ehk=EitDc3GBVYQXV4FPi9KONZCldr1dytqONBe5giQ%2fKlA%3d&risl=&pid=ImgRaw&r=0', 'https://ts1.tc.mm.bing.net/th/id/R-C.4da110c44b9323a0bcb5a92877425c9b?rik=L4P%2bj%2bq%2fg2aLKA&riu=http%3a%2f%2fn.sinaimg.cn%2fsinakd20113%2f607%2fw640h767%2f20210306%2fd62e-kkxpcze0493202.jpg&ehk=EitDc3GBVYQXV4FPi9KONZCldr1dytqONBe5giQ%2fKlA%3d&risl=&pid=ImgRaw&r=0', 113.578234, 23.512456, '广州市从化区温泉镇温泉大道128号', '24小时营业', '020-87899888', 4.6, 1, 200.00, 800.00, '[\"江景房\",\"免费WiFi\",\"免费停车\",\"宠物友好\"]', '24小时营业', 4.7, 4.8, '[\"江景\",\"温泉\",\"早餐\",\"宠物友好\"]', 1, '2025-10-17 18:23:10', '2025-11-17 00:11:57', 0);
INSERT INTO `merchant` VALUES (3, 1973987306786885634, '从化竹艺坊', 2, '专业制作竹制工艺品的传统手工作坊。选用优质楠竹，传承百年工艺，制作各类精美的竹制品：竹篮、竹席、竹编画等。支持定制，欢迎参观制作过程。', 'https://ts1.tc.mm.bing.net/th/id/R-C.e26441ca6db0c2ef8cca28811d79dd8c?rik=uERrwIDVWALqug&riu=http%3a%2f%2fimg.wenlvnews.com%2fa%2f10001%2f202303%2fb3ee3afc0b185788ba1129f46d79bfca.jpeg&ehk=QZrThaONQl8af42851cmcDYFO%2bpmx6EHdAvp9HTd%2f8w%3d&risl=&pid=ImgRaw&r=0', 'https://ts1.tc.mm.bing.net/th/id/R-C.e26441ca6db0c2ef8cca28811d79dd8c?rik=uERrwIDVWALqug&riu=http%3a%2f%2fimg.wenlvnews.com%2fa%2f10001%2f202303%2fb3ee3afc0b185788ba1129f46d79bfca.jpeg&ehk=QZrThaONQl8af42851cmcDYFO%2bpmx6EHdAvp9HTd%2f8w%3d&risl=&pid=ImgRaw&r=0', 113.594567, 23.545678, '广州市从化区太平镇竹艺街99号', '周一至周日 09:00-18:00', '020-87880111', 4.9, 1, 50.00, 1500.00, '[\"纯手工\",\"传统工艺\",\"可定制\"]', '周一至周日 09:00-18:00', 4.8, 4.6, '[\"可参观\",\"可定制\",\"材料包\",\"包邮\"]', 1, '2025-10-17 18:30:00', '2025-11-17 00:12:20', 0);
INSERT INTO `merchant` VALUES (4, 1973987306786885634, '荔枝岭果园', 3, '从化本地有机农场，主要种植荔枝、龙眼、黄皮等岭南特色水果。所有水果均采用有机种植方式，无农药残留，新鲜直供。支持现场采摘和线上订购。', 'https://ts1.tc.mm.bing.net/th/id/R-C.629226cd23836f2118190db783296b70?rik=4r02uHpA1LznWw&riu=http%3a%2f%2fimg.mp.sohu.com%2fupload%2f20180607%2fdc85866508834a09b4b4fdf0c5a3deee_th.jpg&ehk=eW0%2b82BN%2b7TyWEHeE77E8nZzTxDqDEKSZ9r04l09gH4%3d&risl=&pid=ImgRaw&r=0', 'https://ts1.tc.mm.bing.net/th/id/R-C.629226cd23836f2118190db783296b70?rik=4r02uHpA1LznWw&riu=http%3a%2f%2fimg.mp.sohu.com%2fupload%2f20180607%2fdc85866508834a09b4b4fdf0c5a3deee_th.jpg&ehk=eW0%2b82BN%2b7TyWEHeE77E8nZzTxDqDEKSZ9r04l09gH4%3d&risl=&pid=ImgRaw&r=0', 113.602234, 23.523456, '广州市从化区江埔街道荔枝岭村果园路18号', '采摘季：5-9月 08:00-18:00', '020-87880222', 4.7, 1, 25.00, 150.00, '[\"有机种植\",\"现场采摘\",\"新鲜直供\",\"快递到家\"]', '采摘季：5-9月 08:00-18:00', 4.8, 4.5, '[\"有机认证\",\"支持采摘\",\"快递配送\",\"团购优惠\"]', 1, '2025-10-18 00:09:32', '2025-11-17 00:13:10', 0);
INSERT INTO `merchant` VALUES (5, 1973987306786885634, '流溪河游船体验中心', 5, '专业提供流溪河游船观光服务的旅游中心。配备现代化游船设备，提供多种游船路线：日游、夜游、包船等。沿途可欣赏山水风光，领略从化自然之美。', 'https://www.chtour.cn/UpFile/image/20240318/171075157437174.jpg', 'https://www.chtour.cn/UpFile/image/20240318/171075157437174.jpg', 113.572345, 23.538901, '广州市从化区温泉镇流溪河码头', '周一至周日 08:30-17:30', '020-87880333', 4.8, 1, 50.00, 500.00, '[\"游船观光\",\"日游\",\"夜游\",\"包船\",\"团体优惠\"]', '周一至周日 08:30-17:30', 4.9, 4.8, '[\"游船观光\",\"日游夜游\",\"包船服务\",\"团体优惠\",\"安全设备\"]', 1, '2025-10-18 00:15:00', '2025-11-17 00:14:02', 0);

