  INDEX `idx_merchant_id`(`merchant_id` ASC) USING BTREE,
  INDEX `idx_service_type`(`service_type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '商家服务配置表' ROW_FORMAT = DYNAMIC;

