INSERT INTO `post` VALUES (62, 15, '从化温泉全攻略：最全泡汤指南', '详细介绍从化各大温泉度假村的特色，包含碧水湾、望谷温泉等比较...', 'https://th.bing.com/th/id/R.25db83504baa0949cad62d82d6fc61b9?rik=i1xzzKiliR17xw&riu=http%3a%2f%2fpic1.k1u.com%2fk1u%2fmb%2fd%2ffile%2f20201209%2f1607484280483654_836_10000.jpg&ehk=b9bniRzHZkbWTQgmzwkqtYOxTFm6DIiZ%2bzni9I2L9Ao%3d&risl=&pid=ImgRaw&r=0', 12500, 843, 134, 1, '2024-08-15 14:30:00', '2025-11-04 19:49:40', 0, 4);
