INSERT INTO `post` VALUES (88, 47, '从化荔枝节游玩攻略', '最佳采摘时间、果园推荐、荔枝品种区别及购买技巧...', 'https://th.bing.com/th/id/R.c6c0607e9ceb60036018afb49fe31cad?rik=rp4pKFVn1JE76g&riu=http%3a%2f%2fimage2.sina.com.cn%2fdy%2fc%2f2004-07-09%2fU399P1T1D3655681F23DT20040709110043.jpg&ehk=Vt9oUf3syWrH1Pmn256RrbkEi7GPjXE1PAzoILRSmCo%3d&risl=&pid=ImgRaw&r=0', 9200, 1760, 189, 1, '2024-08-02 19:30:00', '2025-10-31 14:22:08', 0, 2);
INSERT INTO `post` VALUES (790, 1971813431033851906, '从化 3天 ✈️', '目的地：从化\n天数：3天\n主题：通用\n\n行程亮点：\n第1天：游览石门国家森林公园，欣赏秋季红叶与瀑布景观，漫步大岭山森林公园，呼吸清新空气\n第2天：探访流溪河国家森林公园，乘船游湖观鸟，骑行流溪绿道，感受沿河风光\n第3天：体验从化特色平价温泉（如天湖温泉或农家温泉客栈），参观钱岗古村，探寻广裕祠历史文化\n\n✨ 已生成精美回忆图，记录这次美好的旅程！\n\nTips：合理安排行程，注意安全出行。', 'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/memory-card/6/2025-11-20_38e7U43sDFAl3WF4.webp', 0, 0, 0, 1, '2025-11-20 19:58:41', '2025-11-20 19:58:41', 0, 1);
INSERT INTO `post` VALUES (791, 1971813431033851906, '新疆 3天 ✈️', '目的地：新疆\n天数：3天\n主题：通用\n\n行程亮点：\n第1天：抵达乌鲁木齐，参观国际大巴扎，体验维吾尔族市集文化，游览红山公园，俯瞰城市全景\n第2天：前往天山天池，欣赏高山湖泊与雪山倒影，徒步小天池环线，感受原始森林与清泉溪流\n第3天：驱车前往吐鲁番，探访火焰山地貌奇观，参观坎儿井水利工程，了解古代灌溉智慧\n\n✨ 已生成精美回忆图，记录这次美好的旅程！\n\nTips：合理安排行程，注意安全出行。', 'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/memory-card/12/2025-11-25_s5x5IKHsRzaAIz9Y.webp', 0, 0, 0, 1, '2025-11-25 18:29:31', '2025-11-25 18:29:31', 0, 1);

-- ----------------------------
-- Table structure for post_tag
-- ----------------------------
DROP TABLE IF EXISTS `post_tag`;
CREATE TABLE `post_tag`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `post_id` bigint NOT NULL COMMENT '关联的帖子ID',
  `tag_id` bigint NOT NULL COMMENT '关联的标签ID',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `is_delete` tinyint NOT NULL DEFAULT 0 COMMENT '是否删除',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_post_tag`(`post_id` ASC, `tag_id` ASC) USING BTREE COMMENT '防止重复关联',
  INDEX `idx_tag_id`(`tag_id` ASC) USING BTREE COMMENT '按标签查询帖子时需要',
  INDEX `idx_is_delete`(`is_delete` ASC) USING BTREE COMMENT '软删除索引'
) ENGINE = InnoDB AUTO_INCREMENT = 44 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '帖子与标签的关联关系' ROW_FORMAT = DYNAMIC;

