-- ----------------------------
-- Table structure for scenic_background
-- ----------------------------
DROP TABLE IF EXISTS `scenic_background`;
CREATE TABLE `scenic_background`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `scenic_spot_id` bigint NOT NULL COMMENT '关联景点ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '背景组名称',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '背景组描述',
  `status` tinyint NULL DEFAULT 1 COMMENT '状态:1-启用,0-禁用',
  `is_default` tinyint(1) NULL DEFAULT 0 COMMENT '是否默认背景组',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `sort_order` int NULL DEFAULT 0 COMMENT '排序值',
  `cover_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '背景组封面图',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_scenic_spot_id`(`scenic_spot_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_is_default`(`is_default` ASC) USING BTREE,
  INDEX `idx_spot_default`(`scenic_spot_id` ASC, `is_default` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '景点背景图片组表' ROW_FORMAT = DYNAMIC;

