-- ----------------------------
-- Table structure for tb_user_quota
-- ----------------------------
DROP TABLE IF EXISTS `tb_user_quota`;
CREATE TABLE `tb_user_quota`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `total_quota` int NOT NULL DEFAULT 10000 COMMENT '总配额（Token数量）',
  `used_quota` int NOT NULL DEFAULT 0 COMMENT '已使用配额',
  `remaining_quota` int NOT NULL DEFAULT 10000 COMMENT '剩余配额',
  `reset_date` date NOT NULL COMMENT '配额重置日期',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_id_date`(`user_id` ASC, `reset_date` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户AI配额表' ROW_FORMAT = DYNAMIC;

