-- ----------------------------
-- Table structure for trip
-- ----------------------------
DROP TABLE IF EXISTS `trip`;
CREATE TABLE `trip`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `destination` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '目的地',
  `days` int NOT NULL COMMENT '天数',
  `budget` int NULL DEFAULT NULL COMMENT '预算（元）',
  `theme` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '主题（如：休闲、探险、文化等）',
  `start_date` datetime NULL DEFAULT NULL COMMENT '开始日期',
  `end_date` datetime NULL DEFAULT NULL COMMENT '结束日期',
  `daily_highlights` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '按天亮点（JSON格式）',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'draft' COMMENT '状态：draft（草稿）、accepted（已接受）、completed（已完成）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_delete` tinyint NOT NULL DEFAULT 0 COMMENT '是否删除（0-未删除，1-已删除）',
  `structured_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '完整结构化数据（JSON格式）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
  INDEX `idx_is_delete`(`is_delete` ASC) USING BTREE,
  INDEX `idx_trip_structured_data`((json_length(`structured_data`)) ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '行程表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of trip
-- ----------------------------
INSERT INTO `trip` VALUES (1, 1971813431033851906, '从化 欣荣宏广场', 1, 500, '', NULL, NULL, '{\"1\":[\"上午游览欣荣宏广场及周边商业街，感受从化城区生活氛围\",\"中午在广场附近品尝从化特色农家菜（推荐：吕田焖大肉、流溪鱼）\",\"下午前往流溪河国家森林公园入口区域散步，享受自然清新空气\",\"傍晚返回欣荣宏广场夜市，体验本地小吃与夜生活\"]}', 'completed', '2025-11-11 20:00:58', '2025-11-11 20:00:58', 0, NULL);
INSERT INTO `trip` VALUES (2, 1971813431033851906, '从化', 2, 1500, '自然风光与温泉养生', NULL, NULL, NULL, 'accepted', '2025-11-12 09:31:40', '2025-11-12 09:31:40', 0, '{\"destination\":\"从化\",\"days\":2,\"budget\":1500,\"theme\":\"自然风光与温泉养生\",\"dailyPlans\":[{\"day\":1,\"date\":\"2024-11-16\",\"activities\":[{\"time\":\"09:00-11:30\",\"name\":\"石门国家森林公园\",\"type\":\"attraction\",\"description\":\"被誉为‘广州香山’，秋季红叶尤为壮观，园内有原始森林、瀑布群和高山草原，适合徒步与摄影。\",\"location\":{\"address\":\"广州市从化区温泉镇石门国家森林公园\",\"coordinates\":[113.7289,23.6891]},\"estimatedCost\":40,\"tips\":[\"建议穿防滑运动鞋\",\"携带饮用水和防晒用品\",\"园区较大，可选择乘坐观光车（另收费20元）\"]},{\"time\":\"14:00-16:30\",\"name\":\"流溪河国家森林公园\",\"type\":\"attraction\",\"description\":\"广州著名的生态景区，湖光山色交相辉映，可乘船游湖或沿栈道漫步，探访梅花谷与三桠塘峡谷。\",\"location\":{\"address\":\"广州市从化区良口镇流溪河国家森林公园\",\"coordinates\":[113.8472,23.6156]},\"estimatedCost\":45,\"tips\":[\"公园内温差较大，建议带薄外套\",\"周末游客较多，建议错峰入园\"]}],\"meals\":[{\"time\":\"12:00-13:00\",\"type\":\"lunch\",\"recommendation\":\"吕田镇农家菜馆 - 推荐吕田焖大肉、山水豆腐、竹筒饭\",\"estimatedCost\":70},{\"time\":\"18:30-19:30\",\"type\":\"dinner\",\"recommendation\":\"温泉镇粤式餐厅 - 尝试从化五指毛桃炖鸡、清蒸水库鱼\",\"estimatedCost\":80}]},{\"day\":2,\"date\":\"2024-11-17\",\"activities\":[{\"time\":\"09:30-11:30\",\"name\":\"北回归线标志塔公园\",\"type\":\"attraction\",\"description\":\"了解地理知识的同时欣赏园林景观，每年夏至正午太阳直射，立竿无影，极具科普意义。\",\"location\":{\"address\":\"从化区太平镇北回归线标志塔公园\",\"coordinates\":[113.5785,23.5487]},\"estimatedCost\":0,\"tips\":[\"免费开放，适合家庭亲子游\",\"早晨光线好，适合拍照\"]},{\"time\":\"13:00-16:00\",\"name\":\"从化温泉度假区泡温泉\",\"type\":\"relaxation\",\"description\":\"体验富含矿物质的天然温泉，缓解疲劳，提升旅行舒适度。推荐选择含多种功能池的温泉酒店公共区域。\",\"location\":{\"address\":\"从化温泉镇温泉东路\",\"coordinates\":[113.7321,23.6905]},\"estimatedCost\":120,\"tips\":[\"自带泳衣毛巾更卫生\",\"避免空腹或饱食后立即泡汤\",\"注意补充水分\"]}],\"meals\":[{\"time\":\"12:00-13:00\",\"type\":\"lunch\",\"recommendation\":\"温泉镇本地茶楼 - 品尝广式早茶点心，如虾饺、凤爪、肠粉\",\"estimatedCost\":60}]}],\"accommodation\":{\"night1\":{\"name\":\"从化温泉镇精品民宿\",\"type\":\"hotel\",\"address\":\"从化区温泉镇温泉东路88号\",\"checkInTime\":\"15:00\",\"checkOutTime\":\"12:00\",\"pricePerNight\":400,\"features\":[\"含早餐\",\"提供免费停车\",\"部分房间带私汤\"]},\"night2\":\"无（次日返程）\"},\"totalEstimatedCost\":1465,\"costBreakdown\":{\"attractions\":105,\"meals\":210,\"accommodation\":400,\"transportation\":350,\"miscellaneous\":400},\"tips\":[\"建议自驾出行，从化各景点间距离较远，公共交通不便\",\"提前通过官方公众号预约景区门票，避免排队\",\"秋冬季节早晚温差大，需准备保暖衣物\",\"温泉泡浴时间每次不超过20分钟，注意身体反应\",\"保护环境，请勿在森林公园内乱扔垃圾\"],\"transportationNotes\":\"广州市区出发约1.5小时车程；若非自驾，可乘坐地铁14号线至从化客运站，再转乘公交或打车前往各景点（费用较高且耗时较长）。\"}');
