INSERT INTO `trip` VALUES (4, 1971813431033851906, '从化', 3, NULL, '', NULL, NULL, '{\"1\":[\"游览石门国家森林公园\",\"观赏秋天的红叶林与峡谷风光\",\"徒步九曲溪栈道\"],\"2\":[\"参观流溪河国家森林公园\",\"乘船游流溪湖\",\"登顶三桠塘幽谷探险\"],\"3\":[\"体验碧水湾温泉度假村\",\"享受多种功效温泉池\",\"返程前品尝从化农家菜\"]}', 'accepted', '2025-11-18 17:28:37', '2025-11-18 17:28:37', 0, NULL);
INSERT INTO `trip` VALUES (5, 1971813431033851906, '从化', 3, 200, '', NULL, NULL, '{\"1\":[\"游览流溪河国家森林公园（外围步道免费）\",\"骑行温泉镇沿河绿道\"],\"2\":[\"探访钱岗古村（免费开放）\",\"漫步三百洞生态度假区外围山林小径\"],\"3\":[\"参观从化农耕文化园（免费）\",\"在街口市场品尝本地小吃并采购特产\"]}', 'completed', '2025-11-18 18:54:15', '2025-11-18 18:54:15', 0, NULL);
INSERT INTO `trip` VALUES (6, 1971813431033851906, '从化', 3, 600, '', '2025-11-22 08:00:00', '2025-11-24 08:00:00', '{\"1\":[\"游览石门国家森林公园，欣赏秋季红叶与瀑布景观\",\"漫步大岭山森林公园，呼吸清新空气\"],\"2\":[\"探访流溪河国家森林公园，乘船游湖观鸟\",\"骑行流溪绿道，感受沿河风光\"],\"3\":[\"体验从化特色平价温泉（如天湖温泉或农家温泉客栈）\",\"参观钱岗古村，探寻广裕祠历史文化\"]}', 'accepted', '2025-11-20 18:33:42', '2025-11-20 18:33:42', 0, NULL);
INSERT INTO `trip` VALUES (7, 1971813431033851906, '从化', 3, 666, '', NULL, NULL, '{\"1\":[\"游览石门国家森林公园，欣赏秋季花海与红叶\",\"徒步九公里环线，探访石门瀑布与原始森林\"],\"2\":[\"参观流溪河国家森林公园，乘船游湖观岛屿\",\"骑行流溪绿道，体验沿河风光与农家乐午餐\"],\"3\":[\"泡从化温泉镇平价温泉（如大金峰温泉或工薪疗养院）\",\"漫步温泉广场，购买当地土特产如桂味荔枝干、蜂蜜\"]}', 'accepted', '2025-11-25 15:47:23', '2025-11-25 15:47:23', 0, NULL);
INSERT INTO `trip` VALUES (8, 1971813431033851906, '北京', 1, 1000, '', NULL, NULL, '{\"1\":[\"参观天安门广场，观看升旗仪式（如早到），感受国家象征的庄严氛围\",\"游览世界最大宫殿建筑群——故宫博物院，深入了解明清皇家历史与文化\",\"登景山公园万春亭，俯瞰故宫全景与北京中轴线\",\"漫步什刹海风景区，体验老北京胡同文化，品尝特色小吃如糖葫芦、豆汁儿焦圈\",\"傍晚在后海欣赏日落，可选择免费沿湖步道或性价比高的茶馆休憩\"]}', 'accepted', '2025-11-25 15:57:47', '2025-11-25 15:57:47', 0, NULL);
INSERT INTO `trip` VALUES (9, 1971813431033851906, '上海', 1, 2000, '', NULL, NULL, '{\"1\":[\"游览外滩，欣赏黄浦江两岸历史建筑与陆家嘴摩天大楼的交汇景观\",\"漫步南京路步行街，体验繁华商业氛围并品尝本地小吃\",\"探访豫园及城隍庙，感受明代古典园林与传统市集文化\",\"登顶上海中心大厦观光厅（118层），俯瞰全城壮丽景色\",\"傍晚乘坐黄浦江游船，欣赏两岸璀璨夜景\"]}', 'accepted', '2025-11-25 18:07:59', '2025-11-25 18:07:59', 0, NULL);
INSERT INTO `trip` VALUES (10, 1971813431033851906, '魔都', 1, 1000, '', NULL, NULL, '{\"1\":[\"游览外滩，欣赏黄浦江两岸历史建筑与陆家嘴现代天际线\",\"漫步南京路步行街，体验繁华商业氛围并品尝特色小吃\",\"探访豫园和城隍庙，感受江南古典园林与民俗文化\",\"登顶上海中心大厦观光厅（118层），俯瞰魔都全景\",\"夜游黄浦江，观赏两岸灯光璀璨的夜景\"]}', 'accepted', '2025-11-25 18:16:10', '2025-11-25 18:16:10', 0, NULL);
INSERT INTO `trip` VALUES (11, 1971813431033851906, '天龙人', 4, 22222, '', NULL, NULL, '{\"1\":[\"抵达天龙圣域·云顶迎宾馆，由白袍仪仗队举行净心仪式\",\"夜宿悬浮于悬崖之上的透明穹顶水晶宫，俯瞰星河\"],\"2\":[\"探访千年禁地‘龙语石林’，聆听古老祭司吟诵天龙密文\",\"乘坐金鳞飞舟穿越‘九重雾渊’，观赏空中瀑布奇景\"],\"3\":[\"参与‘星辰宴’——由七位御厨联合呈献的十二道灵食材盛宴\",\"在‘镜湖之心’进行冥想仪式，体验与远古天龙意识共鸣\"],\"4\":[\"获赠‘龙血玉玺’信物，签署《天龙盟约》成为荣誉族裔\",\"乘彩虹气流舱返回凡界，途中享用云端告别茶会\"]}', 'accepted', '2025-11-25 18:21:49', '2025-11-25 18:21:49', 0, NULL);
INSERT INTO `trip` VALUES (12, 1971813431033851906, '新疆', 3, 11111, '', NULL, NULL, '{\"1\":[\"抵达乌鲁木齐，参观国际大巴扎，体验维吾尔族市集文化\",\"游览红山公园，俯瞰城市全景\"],\"2\":[\"前往天山天池，欣赏高山湖泊与雪山倒影\",\"徒步小天池环线，感受原始森林与清泉溪流\"],\"3\":[\"驱车前往吐鲁番，探访火焰山地貌奇观\",\"参观坎儿井水利工程，了解古代灌溉智慧\"]}', 'accepted', '2025-11-25 18:27:18', '2025-11-25 18:27:18', 0, NULL);

-- ----------------------------
-- Table structure for trip_photo
-- ----------------------------
DROP TABLE IF EXISTS `trip_photo`;
CREATE TABLE `trip_photo`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `trip_id` bigint NOT NULL COMMENT '行程ID',
  `photo_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '照片URL',
  `shot_time` datetime NULL DEFAULT NULL COMMENT '拍摄时间（可选）',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '照片描述（可选）',
  `sort_order` int NOT NULL DEFAULT 0 COMMENT '排序顺序',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_delete` tinyint NOT NULL DEFAULT 0 COMMENT '是否删除（0-未删除，1-已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_trip_id`(`trip_id` ASC) USING BTREE,
  INDEX `idx_sort_order`(`sort_order` ASC) USING BTREE,
  INDEX `idx_is_delete`(`is_delete` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 25 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '行程照片表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of trip_photo
-- ----------------------------
