-- ----------------------------
-- Table structure for wall_background
-- ----------------------------
DROP TABLE IF EXISTS `wall_background`;
CREATE TABLE `wall_background`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `group_id` bigint NOT NULL COMMENT '关联背景组ID',
  `image_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '背景图片URL',
  `thumbnail_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '缩略图URL',
  `background_type` tinyint NULL DEFAULT 1 COMMENT '背景类型:1-白天,2-夜晚,3-季节限定',
  `sort_order` int NULL DEFAULT 0 COMMENT '排序值',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `status` tinyint NULL DEFAULT 1 COMMENT '状态:1-启用,0-禁用',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `is_delete` tinyint NULL DEFAULT 0 COMMENT '是否删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_group_id`(`group_id` ASC) USING BTREE,
  INDEX `idx_sort`(`sort_order` DESC) USING BTREE,
  INDEX `idx_group_type`(`group_id` ASC, `background_type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '留言墙背景图片表' ROW_FORMAT = DYNAMIC;

